INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('fc145db2-7601-4cdd-86b7-e691886df142', 'santa-fe', 'Santa Fe', 'New Mexico', 'Annapurna''s World Vegetarian Cafe', 'Ayurvedic · Vegetarian/Vegan · 1624 Cerrillos Rd', '["vegan", "walkin"]', '[{"cls": "badge-vegan", "text": "🌱 Fully Vegan / Vegetarian"}, {"cls": "badge-walkin", "text": "🚶 Walk-in OK"}]', NULL, NULL, 'Cardamom pancakes with coconut and almonds, best chai in Santa Fe. Full GF/DF bakery. Opens 7 AM — ideal departure-day breakfast before heading to the airport.', '[{"cls": "link-menu", "href": "https://www.chaishoppe.com/menu", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://www.chaishoppe.com", "text": "🌐 Website"}]');
