INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('3647ce6c-eab5-454f-8e98-631f20329a5f', 'santa-fe', 'Santa Fe', 'New Mexico', 'Arroyo Vino', 'Farm-to-Table · 218 Camino La Tierra', '["vegan", "meat", "reserve", "chase"]', '[{"cls": "badge-vegan", "text": "🌿 Vegan-Friendly"}, {"cls": "badge-meat", "text": "🥩 Carnivore Pick"}, {"cls": "badge-res", "text": "📅 Reserve 1–2 weeks ahead"}]', '⚡ Chase', '⚠️ Tue–Sat only, seatings 5–8 PM. Book before Opera night (Jul 14).', 'Seasonal farm-to-table with an attached wine shop. Always has a veggie main. Best sunset views in Santa Fe. Great pre-Opera dinner. Kitchen garden sourced.', '[{"cls": "link-opentable", "href": "https://www.opentable.com/arroyo-vino", "text": "🔴 OpenTable"}, {"cls": "link-menu", "href": "https://arroyovino.com", "text": "📋 Menu (seasonal)"}, {"cls": "link-website", "href": "https://arroyovino.com", "text": "🌐 Website"}]');
