INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('2d6a5c1b-489e-4a07-b0c9-c21deafd35ff', 'santa-fe', 'Santa Fe', 'New Mexico', 'The Bull Ring', 'Classic Chophouse · 150 Washington Ave', '["meat", "walkin"]', '[{"cls": "badge-meat", "text": "🥩 Carnivore Pick"}, {"cls": "badge-walkin", "text": "🚶 Walk-in OK"}]', NULL, NULL, 'Santa Fe institution since 1975. Prime rib, classic cuts, full bar, power lunch crowd. Good late-night option near the Plaza. Longtime local favorite.', '[{"cls": "link-menu", "href": "https://www.thebullringsantafe.com/menu", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://www.thebullringsantafe.com", "text": "🌐 Website"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('2d6a5c1b-489e-4a07-b0c9-c21deafd35ff', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('b035b258-87d6-4207-89ee-6df795bd461e', 'santa-fe', 'Santa Fe', 'New Mexico', 'Cafecito', 'Casual · Vegan-Friendly · 500 Old Santa Fe Trail', '["vegan", "walkin"]', '[{"cls": "badge-vegan", "text": "🌱 Fully Vegan Options"}, {"cls": "badge-walkin", "text": "🚶 Walk-in OK"}]', NULL, NULL, 'Beautiful patio, vegan "three sisters" empanadas, De La Tierra bowl (lentils, cauliflower, beets, squash, kale). Great lunch spot near Museum Hill.', '[{"cls": "link-menu", "href": "https://cafecitosantafe.com/menu", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://cafecitosantafe.com", "text": "🌐 Website"}, {"cls": "link-call", "href": "tel:+15059860500", "text": "📞 Call"}]');
