INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('64d4b1b6-9e0a-4929-b277-c2cf2fd64dc2', 'santa-fe', 'Santa Fe', 'New Mexico', 'El Farol', 'Spanish Tapas · Canyon Road · 808 Canyon Rd', '["vegan", "meat", "walkin"]', '[{"cls": "badge-vegan", "text": "🌿 Vegan-Friendly"}, {"cls": "badge-meat", "text": "🥩 Carnivore Pick"}, {"cls": "badge-walkin", "text": "🚶 Bar walk-in"}]', NULL, NULL, 'Spanish tapas with flamenco dancing and live entertainment on Canyon Road. Vegan options among the small plates. Great last-night vibe. Oldest restaurant in Santa Fe.', '[{"cls": "link-menu", "href": "https://elfarolsf.com/menus/", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://elfarolsf.com", "text": "🌐 Website"}, {"cls": "link-call", "href": "tel:+15059839912", "text": "📞 Call for Res"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('64d4b1b6-9e0a-4929-b277-c2cf2fd64dc2', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('015e498a-22a8-4f61-b944-c7a7b35d23a8', 'santa-fe', 'Santa Fe', 'New Mexico', 'Geronimo', 'Fine Dining · Canyon Road · 724 Canyon Rd', '["vegan", "meat", "reserve", "chase"]', '[{"cls": "badge-vegan", "text": "🌿 Vegan-Friendly"}, {"cls": "badge-meat", "text": "🥩 Carnivore Pick"}, {"cls": "badge-res", "text": "📅 Reserve ASAP"}]', '⚡ Chase', '⚠️ Books 2–3 weeks out in July. Reserve immediately.', 'NM''s only Mobil 4-Star & AAA 4-Diamond. Elk tenderloin, bison, seasonal vegetarian tasting menu. 1756 adobe home on Canyon Road. Best last-night splurge in Santa Fe.', '[{"cls": "link-opentable", "href": "https://www.opentable.com/geronimo-santa-fe", "text": "🔴 OpenTable"}, {"cls": "link-menu", "href": "https://www.geronimorestaurant.com/menu", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://www.geronimorestaurant.com", "text": "🌐 Website"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('015e498a-22a8-4f61-b944-c7a7b35d23a8', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('d06e3f27-eae0-42cc-af7b-3ce3a4844b69', 'santa-fe', 'Santa Fe', 'New Mexico', 'Horno Restaurant', 'Gastropub · Near Plaza · 95 W Marcy St', '["vegan", "meat", "reserve", "chase"]', '[{"cls": "badge-vegan", "text": "🌿 Vegan-Friendly"}, {"cls": "badge-meat", "text": "🥩 Carnivore Pick"}, {"cls": "badge-res", "text": "📅 Reserve a few days ahead"}]', '⚡ Chase', NULL, 'James Beard-nominated Chef David Sellers. Upscale gastropub, seasonal world-inspired small plates. Vegan dumplings + vegan chocolate cake. Al fresco patio. Steps from the Plaza.', '[{"cls": "link-opentable", "href": "https://www.opentable.com/r/horno-restaurant-santa-fe", "text": "🔴 OpenTable"}, {"cls": "link-menu", "href": "https://www.hornorestaurant.com/menu", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://www.hornorestaurant.com", "text": "🌐 Website"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('d06e3f27-eae0-42cc-af7b-3ce3a4844b69', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('5aabc662-a0dc-4243-adda-9ae2b45e897f', 'santa-fe', 'Santa Fe', 'New Mexico', 'La Plazuela at La Fonda', 'New Mexican · Inside La Fonda on the Plaza · 100 E San Francisco St', '["meat", "reserve", "chase"]', '[{"cls": "badge-meat", "text": "🥩 Carnivore Pick"}, {"cls": "badge-res", "text": "📅 Reserve for dinner"}]', '⚡ Chase', '⚠️ Breakfast & lunch are walk-in only; dinner reservations recommended.', 'Historic 1920s indoor courtyard with skylights, steps from the Plaza. Innovative New Mexican classics — tortilla soup, tableside guacamole, enchiladas, filet mignon. Santa Fe''s most romantic dining room.', '[{"cls": "link-opentable", "href": "https://www.opentable.com/la-plazuela-at-la-fonda-on-the-plaza", "text": "🔴 OpenTable"}, {"cls": "link-menu", "href": "https://lafondasantafe.com/dinner-menu/", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://lafondasantafe.com/la-plazuela/", "text": "🌐 Website"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('5aabc662-a0dc-4243-adda-9ae2b45e897f', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('6312ba22-5a1c-41d7-b5ed-6df059038e42', 'santa-fe', 'Santa Fe', 'New Mexico', 'Paloma', 'Contemporary Mexican · 401 S Guadalupe St', '["vegan", "meat", "reserve", "chase"]', '[{"cls": "badge-vegan", "text": "🌿 Vegan-Friendly"}, {"cls": "badge-meat", "text": "🥩 Carnivore Pick"}, {"cls": "badge-res", "text": "📅 Reserve same/next day"}]', '⚡ Chase', NULL, 'Scratch-made masa, mezcal-forward bar, vivid Mexican-inspired menu. Cauliflower dishes for vegans, solid meat mains. Free parking after 6 PM. Open late kitchen.', '[{"cls": "link-opentable", "href": "https://www.opentable.com/r/paloma-santa-fe", "text": "🔴 OpenTable"}, {"cls": "link-menu", "href": "https://paloma-sf.com/menus", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://paloma-sf.com", "text": "🌐 Website"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('6312ba22-5a1c-41d7-b5ed-6df059038e42', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('a4da8969-2ab3-4cfd-8f11-1bc7659a985c', 'santa-fe', 'Santa Fe', 'New Mexico', 'Restaurant Martin', 'Fine Dining · Contemporary American · 526 Galisteo St', '["vegan", "meat", "reserve", "chase"]', '[{"cls": "badge-vegan", "text": "🌿 Vegan-Friendly"}, {"cls": "badge-meat", "text": "🥩 Carnivore Pick"}, {"cls": "badge-res", "text": "📅 Reserve ahead"}]', '⚡ Chase', NULL, 'James Beard finalist for Best Chef Southwest (multiple years). French technique meets NM ingredients. Organic meats, local produce. Beautiful patio. Family-owned.', '[{"cls": "link-opentable", "href": "https://www.opentable.com/restaurant-martin", "text": "🔴 OpenTable"}, {"cls": "link-menu", "href": "https://restaurantmartinsantafe.com/menus/", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://restaurantmartinsantafe.com", "text": "🌐 Website"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('a4da8969-2ab3-4cfd-8f11-1bc7659a985c', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('eb16ec51-b863-41d4-8f15-140732286ab1', 'santa-fe', 'Santa Fe', 'New Mexico', 'Rio Chama Prime Steakhouse', 'Steakhouse · 414 Old Santa Fe Trail', '["meat", "walkin"]', '[{"cls": "badge-meat", "text": "🥩 Carnivore Pick"}, {"cls": "badge-walkin", "text": "🚶 Bar seating available"}]', NULL, NULL, 'Santa Fe''s top steakhouse. Prime rib, bone-in ribeye, filet mignon, oysters to start. Great for pre-Opera dinner. Full bar. Classic Santa Fe atmosphere.', '[{"cls": "link-menu", "href": "https://www.riochamasteakhouse.com/menu", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://www.riochamasteakhouse.com", "text": "🌐 Website"}, {"cls": "link-call", "href": "tel:+15059554949", "text": "📞 Call for Res"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('eb16ec51-b863-41d4-8f15-140732286ab1', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('7d064bdd-c596-4f8c-a933-acace5d3d4a9', 'santa-fe', 'Santa Fe', 'New Mexico', 'Santa Fe Teahouse & Bistro', 'Bistro · Top of Canyon Road · 821 Canyon Rd', '["vegan", "reserve", "chase"]', '[{"cls": "badge-vegan", "text": "🌿 Vegan-Friendly"}, {"cls": "badge-res", "text": "📅 Reserve or walk-in"}]', '⚡ Chase', NULL, '80+ teas, espresso drinks, and tea-infused cocktails from a 99% gluten-free scratch kitchen with vegetarian and vegan options. Dog-friendly garden patio, frequent live music. Open Wed–Sun, 8 AM–3 PM.', '[{"cls": "link-opentable", "href": "https://www.opentable.com/r/santa-fe-teahouse-and-bistro-santa-fe", "text": "🔴 OpenTable"}, {"cls": "link-menu", "href": "https://www.santafeteahouse.com/pages/breakfast", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://www.santafeteahouse.com", "text": "🌐 Website"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('7d064bdd-c596-4f8c-a933-acace5d3d4a9', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('eaebd19c-4cf3-4b92-a5c0-165d1de3307e', 'santa-fe', 'Santa Fe', 'New Mexico', 'Sweetwater Harvest Kitchen', 'Vegan / GF · 1512 Pacheco St', '["vegan", "walkin"]', '[{"cls": "badge-vegan", "text": "🌱 Fully Vegan"}, {"cls": "badge-walkin", "text": "🚶 Walk-in OK"}]', NULL, NULL, 'Dedicated gluten-free facility. Daily specials, mushroom tea lattes, vegan and paleo options. Fine dining quality meets cozy café vibe. Great for breakfast or lunch.', '[{"cls": "link-menu", "href": "https://www.sweetwaterharvestkitchen.com/menu", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://www.sweetwaterharvestkitchen.com", "text": "🌐 Website"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('eaebd19c-4cf3-4b92-a5c0-165d1de3307e', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('e2439cf8-4ef6-496b-96de-3abd01edb1ce', 'santa-fe', 'Santa Fe', 'New Mexico', 'Tomasita''s', 'Classic NM · 500 S Guadalupe St', '["vegan", "walkin"]', '[{"cls": "badge-vegan", "text": "🌿 Vegan-Friendly"}, {"cls": "badge-walkin", "text": "🚶 Walk-in (expect wait)"}]', NULL, NULL, 'Best beans in Santa Fe (vegan). Authentic New Mexican: green/red chile, smothered burritos, enchiladas. No-frills, cash-only vibe. Locals love it. Expect a line.', '[{"cls": "link-menu", "href": "https://www.tomasitas.com/menu", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://www.tomasitas.com", "text": "🌐 Website"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('e2439cf8-4ef6-496b-96de-3abd01edb1ce', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('12849b90-5bdb-45eb-bafa-82bc2a7ed5cb', 'taos', 'Taos', 'New Mexico', '5 Star Burgers', 'Burgers · 1032 Paseo Del Pueblo Sur', '["meat", "walkin"]', '[{"cls": "badge-meat", "text": "🥩 Carnivore Pick"}, {"cls": "badge-walkin", "text": "🚶 Walk-in OK"}]', NULL, NULL, 'USA Today "Best Burger in New Mexico." Hormone-free Angus beef ground daily. Green chile cheeseburger is the move. Casual, quick, excellent. Great lunch before driving to ABQ.', '[{"cls": "link-menu", "href": "https://www.5starburgers.com/menu", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://www.5starburgers.com", "text": "🌐 Website"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('12849b90-5bdb-45eb-bafa-82bc2a7ed5cb', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('ec538e52-31df-4f80-b92b-f12b8c2d54e9', 'taos', 'Taos', 'New Mexico', 'Bent Street Grille', 'American Bistro · 120 Bent St', '["vegan", "meat", "walkin"]', '[{"cls": "badge-vegan", "text": "🌿 Vegan-Friendly"}, {"cls": "badge-meat", "text": "🥩 Carnivore Pick"}, {"cls": "badge-walkin", "text": "🚶 Walk-in OK"}]', NULL, NULL, 'Casual country-style brunch & lunch. Authentic northern NM flavors, scratch-made sauces. Best breakfast/lunch spot in Taos. Vegan and meat options throughout.', '[{"cls": "link-menu", "href": "https://bentstreetgrille.com/menu", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://bentstreetgrille.com", "text": "🌐 Website"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('ec538e52-31df-4f80-b92b-f12b8c2d54e9', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('0c9cd289-1b31-4e49-b9b2-b089db042b32', 'taos', 'Taos', 'New Mexico', 'La Luna @ La Fonda', 'Indigenous Fine Dining · Taos Plaza', '["vegan", "meat", "reserve"]', '[{"cls": "badge-vegan", "text": "🌿 Vegan-Friendly"}, {"cls": "badge-meat", "text": "🥩 Carnivore Pick"}, {"cls": "badge-res", "text": "📅 Reserve ahead"}]', NULL, NULL, 'One of only a handful of US restaurants dedicated to elevated Indigenous cuisine. Ancestral ingredients from North, Central and South America. Unique & unforgettable.', '[{"cls": "link-menu", "href": "https://lafondetaos.com/dining", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://lafondetaos.com", "text": "🌐 Website"}, {"cls": "link-call", "href": "tel:+15757582211", "text": "📞 Call for Res"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('0c9cd289-1b31-4e49-b9b2-b089db042b32', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('1017baf5-64ea-478b-858c-c1566d7538f4', 'taos', 'Taos', 'New Mexico', 'Lambert''s of Taos', 'Fine Dining · 309 Paseo Del Pueblo Sur', '["meat", "reserve"]', '[{"cls": "badge-meat", "text": "🥩 Carnivore Pick"}, {"cls": "badge-res", "text": "📅 Reserve ahead (Las Fiestas wknd)"}]', NULL, '⚠️ Very busy Jul 17–19 during Las Fiestas. Book in advance.', 'Fine dining since 1989. CAB petit filet mignon, duck breast, buffalo tenderloin. Tree-shaded patio. Upscale but relaxed. Taos''s most reliable fine dining institution.', '[{"cls": "link-menu", "href": "https://lambertsoftaos.com/menu", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://lambertsoftaos.com", "text": "🌐 Website"}, {"cls": "link-call", "href": "tel:+15757589009", "text": "📞 Call for Res"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('1017baf5-64ea-478b-858c-c1566d7538f4', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('1c4f5cba-c0c1-4df9-9d97-33453400a96f', 'taos', 'Taos', 'New Mexico', 'The Love Apple', 'Organic · Farm-to-Table · 803 Paseo Del Pueblo Norte', '["vegan", "meat", "reserve"]', '[{"cls": "badge-vegan", "text": "🌿 Vegan-Friendly"}, {"cls": "badge-meat", "text": "🥩 Carnivore Pick"}, {"cls": "badge-res", "text": "📅 Reserve ASAP · Phone Only"}]', NULL, '⚠️ No OpenTable — call (575) 751-0050. Fills every night in July. Reserve now.', 'Intimate restaurant in a converted 1800s chapel. Gnocchi with carrot butter (vegan), duck breast, lamb albondigas. Wed–Sun, 5–9 PM only. One of the best in NM.', '[{"cls": "link-menu", "href": "https://theloveapple.net/pdf/love_apple_taos_dinner_menu.pdf", "text": "📋 Menu (PDF)"}, {"cls": "link-website", "href": "https://theloveapple.net", "text": "🌐 Website"}, {"cls": "link-phone", "href": "tel:+15757510050", "text": "📞 (575) 751-0050"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('1c4f5cba-c0c1-4df9-9d97-33453400a96f', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('aa985ece-d4db-4810-b16f-3d67f1b5e867', 'albuquerque', 'Albuquerque', 'New Mexico', 'Annapurna''s World Vegetarian Cafe', 'Ayurvedic · Multiple Locations', '["vegan", "walkin"]', '[{"cls": "badge-vegan", "text": "🌱 Fully Vegan / Vegetarian"}, {"cls": "badge-walkin", "text": "🚶 Walk-in OK"}]', NULL, NULL, 'Ayurvedic Indian — cardamom pancakes, tofu scramble, South Indian sampler, Lebanese wrap. GF and sugar-free bakery. Where this mini-chain started (2002). Multiple ABQ locations.', '[{"cls": "link-menu", "href": "https://www.chaishoppe.com/menu", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://www.chaishoppe.com", "text": "🌐 Website"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('aa985ece-d4db-4810-b16f-3d67f1b5e867', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('b144ad1c-8c77-4f3a-bd95-b8f6f51ce524', 'albuquerque', 'Albuquerque', 'New Mexico', 'Antiquity Restaurant', 'Wild Game · Steakhouse · Old Town · 112 Romero St NW', '["meat", "walkin"]', '[{"cls": "badge-meat", "text": "🥩 Carnivore Pick"}, {"cls": "badge-walkin", "text": "🚶 Walk-in OK"}]', NULL, NULL, 'Old Town ABQ institution in a landmark 1785 building. Wild game, seasonal meats, hand-crafted margaritas. 47+ years serving exceptional steaks in a historic adobe. Santos lounge inside.', '[{"cls": "link-menu", "href": "https://www.antiquityrestaurant.com/menu", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://www.antiquityrestaurant.com", "text": "🌐 Website"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('b144ad1c-8c77-4f3a-bd95-b8f6f51ce524', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('a05c3518-bef4-4875-b458-32d6360dfaac', 'albuquerque', 'Albuquerque', 'New Mexico', 'Artichoke Cafe', 'Contemporary American · 424 Central Ave SE', '["vegan", "meat", "reserve"]', '[{"cls": "badge-vegan", "text": "🌿 Vegan-Friendly"}, {"cls": "badge-meat", "text": "🥩 Carnivore Pick"}, {"cls": "badge-res", "text": "📅 Reserve for weekends"}]', NULL, NULL, 'One of ABQ''s most beloved gathering places. New American with French/Italian influences. Always a vegan option on the rotating menu. Great wine bar. Retro-cool EDO neighborhood.', '[{"cls": "link-menu", "href": "https://www.artichokecafe.com/menu", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://www.artichokecafe.com", "text": "🌐 Website"}, {"cls": "link-call", "href": "tel:+15052431301", "text": "📞 Call for Res"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('a05c3518-bef4-4875-b458-32d6360dfaac', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('8231c7bb-5e67-4032-be69-d0a1e0a0db4b', 'albuquerque', 'Albuquerque', 'New Mexico', 'Campo at Los Poblanos', 'Farm-to-Table · 4803 Rio Grande Blvd NW', '["vegan", "meat", "reserve", "chase"]', '[{"cls": "badge-vegan", "text": "🌿 Vegan-Friendly"}, {"cls": "badge-meat", "text": "🥩 Carnivore Pick"}, {"cls": "badge-res", "text": "📅 Reserve 2–3 weeks out"}]', '⚡ Chase', '⚠️ Most sought-after reservation in ABQ. Book immediately for Jul 18 or 19.', 'Farm-to-table on 10-acre organic lavender farm. Rio Grande Valley cuisine, seasonal organic ingredients. Stunning outdoor patio. Vegan and meat dishes equally exceptional.', '[{"cls": "link-website", "href": "https://lospoblanos.com/dining/campo-reservations", "text": "🔴 Reserve Online"}, {"cls": "link-menu", "href": "https://lospoblanos.com/dining/campo-menus", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://lospoblanos.com", "text": "🌐 Website"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('8231c7bb-5e67-4032-be69-d0a1e0a0db4b', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('0f05e1b1-e923-4367-b092-7e034fc5c293', 'albuquerque', 'Albuquerque', 'New Mexico', 'Char at Hotel Andaluz', 'Contemporary NM · 125 2nd St NW', '["meat", "reserve", "chase"]', '[{"cls": "badge-meat", "text": "🥩 Carnivore Pick"}, {"cls": "badge-res", "text": "📅 Reserve on weekends"}]', '⚡ Chase', NULL, 'NM''s only Josper charcoal grill. Live-fire meats and contemporary NM cuisine. Built inside Conrad Hilton''s 1939 hotel. Rooftop G. Toti bar with skyline views. Best hotel dining in ABQ.', '[{"cls": "link-menu", "href": "https://hotelandaluz.com/dining/char", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://hotelandaluz.com/dining", "text": "🌐 Website"}, {"cls": "link-call", "href": "tel:+15052423900", "text": "📞 Call for Res"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('0f05e1b1-e923-4367-b092-7e034fc5c293', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('90cb7eee-3b09-4a09-9a0c-7d34a4aa0cc3', 'albuquerque', 'Albuquerque', 'New Mexico', 'Farina Pizza', 'Pizza · 510 Central Ave SE', '["vegan", "meat", "walkin"]', '[{"cls": "badge-vegan", "text": "🌱 Vegan Options"}, {"cls": "badge-meat", "text": "🥩 Carnivore Pick"}, {"cls": "badge-walkin", "text": "🚶 Walk-in OK"}]', NULL, NULL, 'Potentially the best pizza outside NYC. Vegan cheese and vegan crusts available. Lively bar, Nob Hill neighborhood energy. Next-door sister restaurant to Artichoke Cafe.', '[{"cls": "link-menu", "href": "https://www.farinabistro.com/menu", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://www.farinabistro.com", "text": "🌐 Website"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('90cb7eee-3b09-4a09-9a0c-7d34a4aa0cc3', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('dace7814-6dd2-44c0-af39-b360c14f80ec', 'albuquerque', 'Albuquerque', 'New Mexico', 'Itality: Plant Based Foods', 'Indigenous Vegan · 2500 12th St NW, Unit E', '["vegan", "walkin"]', '[{"cls": "badge-vegan", "text": "🌱 Fully Vegan"}, {"cls": "badge-walkin", "text": "🚶 Counter Service"}]', NULL, NULL, 'Indigenous vegan restaurant in Avanyu Plaza. NDN tacos with fry bread, blue corn waffles, OG nachos supreme with quinoa. Counter-order, dine-in patio or to-go. No reservations — call ahead to confirm hours (Wed–Sun).', '[{"cls": "link-menu", "href": "https://www.italitynm.com/menu", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://www.italitynm.com", "text": "🌐 Website"}, {"cls": "link-call", "href": "tel:+15054512861", "text": "📞 Call"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('dace7814-6dd2-44c0-af39-b360c14f80ec', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('6bdaf9c9-0286-433e-9ddc-754a9935b321', 'albuquerque', 'Albuquerque', 'New Mexico', 'Seasons Rotisserie & Grill', 'Casual Elegant · Old Town · 2031 Mountain Rd NW', '["vegan", "meat", "reserve", "chase"]', '[{"cls": "badge-vegan", "text": "🌿 Vegan-Friendly"}, {"cls": "badge-meat", "text": "🥩 Carnivore Pick"}, {"cls": "badge-res", "text": "📅 Reserve on weekends"}]', '⚡ Chase', NULL, 'ABQ''s top mixed-diet restaurant. Wood-burning rotisserie, Kobe ribeye, jumbo scallops, vegan polenta. Rooftop patio with Happy Hour Wed–Sun. Overlooks Old Town.', '[{"cls": "link-opentable", "href": "https://www.opentable.com/r/seasons-rotisserie-and-grill-albuquerque", "text": "🔴 OpenTable"}, {"cls": "link-menu", "href": "https://www.seasonsabq.com/menu", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://www.seasonsabq.com", "text": "🌐 Website"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('6bdaf9c9-0286-433e-9ddc-754a9935b321', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('b438ee52-323e-47f0-9ce8-cd9ed99ea5b3', 'albuquerque', 'Albuquerque', 'New Mexico', 'Squeezed Juice Bar', 'Raw / Juice Bar · Northeast Heights', '["vegan", "walkin"]', '[{"cls": "badge-vegan", "text": "🌱 Raw / Vegan"}, {"cls": "badge-walkin", "text": "🚶 Walk-in OK"}]', NULL, NULL, 'Best raw food stop in ABQ. Locally owned, farm-to-table fresh juices, acai bowls, smoothies. Fully vegetarian with strong vegan options. Great morning stop.', '[{"cls": "link-menu", "href": "https://squeezedjuicebar.com/menu", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://squeezedjuicebar.com", "text": "🌐 Website"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('b438ee52-323e-47f0-9ce8-cd9ed99ea5b3', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('2001ebf0-470a-4cc7-b846-e693e03feed7', 'albuquerque', 'Albuquerque', 'New Mexico', 'Vegos', 'Plant-Based Mexican · Nob Hill', '["vegan", "walkin"]', '[{"cls": "badge-vegan", "text": "🌱 Fully Vegan"}, {"cls": "badge-walkin", "text": "🚶 Walk-in OK · Wed–Sun"}]', NULL, NULL, 'Plant-based Mexican with authentic spices. Papaya salad and fresh rolls great for raw vegans. Local favorite. Open Wed–Sun only — plan ahead for your ABQ weekend.', '[{"cls": "link-menu", "href": "https://vegosabq.com/menu", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://vegosabq.com", "text": "🌐 Website"}]');
