INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('d8bf7d17-39ac-43b2-bcf0-630a184eb06e', 'albuquerque', 'Albuquerque', 'New Mexico', 'Vintage 423', 'Steakhouse · 423 Central Ave NW', '["vegan", "meat", "reserve", "chase"]', '[{"cls": "badge-meat", "text": "🥩 Carnivore Pick"}, {"cls": "badge-res", "text": "📅 Reserve ahead on weekends"}]', '⚡ Chase', NULL, 'ABQ''s premier steakhouse. USDA Prime & Choice cuts, Wine Spectator-honored wine list, craft cocktails. "Best filet in a long while." Upscale but welcoming. Downtown Route 66.', '[{"cls": "link-opentable", "href": "https://www.opentable.com/vintage-423-reservations-albuquerque", "text": "🔴 OpenTable"}, {"cls": "link-menu", "href": "https://vintage423.com/menu", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://vintage423.com", "text": "🌐 Website"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('d8bf7d17-39ac-43b2-bcf0-630a184eb06e', 0, NULL, NULL);
INSERT INTO restaurants (id, city, city_label, state, name, type, tags, badges, chase, res_note, desc, links) VALUES ('b28b9e06-191b-4ec4-b34f-12994de1535a', 'new-york-city', 'New York City', 'New York', 'Ambassadors Clubhouse', 'Northern Indian · NoMad · 1245 Broadway', '["meat", "reserve"]', '[{"cls": "badge-meat", "text": "🥩 Carnivore Pick"}, {"cls": "badge-res", "text": "📅 Reserve via Resy only"}]', NULL, '⚠️ No OpenTable, phone, or walk-in (except same-day cancellations). Resy releases tables twice a month: 1st for days 1–15, 15th for the rest of the month.', 'Punjab-inspired Northern Indian cuisine — papads & chaat, tandoor & kebabs, biryani & pilau — served with theatrical tableside flair in Manhattan''s NoMad neighborhood.', '[{"cls": "link-resy", "href": "https://resy.com/cities/new-york-ny/venues/ambassadors-clubhouse-new-york", "text": "⚫ Resy"}, {"cls": "link-menu", "href": "https://ambassadorsclubhouse.com/newyork/food-drink/", "text": "📋 Menu"}, {"cls": "link-website", "href": "https://ambassadorsclubhouse.com/newyork/", "text": "🌐 Website"}]');
INSERT INTO notes (restaurant_id, visited, rating, notes) VALUES ('b28b9e06-191b-4ec4-b34f-12994de1535a', 0, NULL, NULL);
